class Solution:
    def countComponents(self, n: int, edges: List[List[int]]) -> int:
        visited = [False] * n
        count = 0
        for i in range(n):
            if not visited[i]:
                count += 1
                self._DFS(i, visited, edges)
        return count

    def _DFS(self, node, visited, edges):
        visited[node] = True
        for child in edges[node]:
            if not visited[child]:
                self._DFS(child, visited, edges)

solutions.cpp:
class Solution {
public:
    int countComponents(int n, vector<vector<int>>& edges) {
        vector<bool> visited(n);
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                DFS(i, visited, edges);
            }
        }
        return count;
    }

    void DFS(int node, vector<bool>& visited, vector<vector<int>>& edges) {
        visited[node] = true;
        for (int child : edges[node]) {
            if (!visited[child]) {
                DFS(child, visited, edges);
            }
        }
    }
};
